"use client";
import { useState } from "react";
import Header from "@/components/Header";
import AboutModal from "@/components/AboutModal";

export default function DashboardPage() {
    const [activeTab, setActiveTab] = useState("issues");
    const [showAbout, setShowAbout] = useState(false);

    const issues = [
        { book: "Война и мир", issued: "2026-03-15", due: "2026-04-15", returned: null, ext: 1, status: "active" },
        { book: "1984", issued: "2026-03-20", due: "2026-04-20", returned: null, ext: 0, status: "active" },
        { book: "Евгений Онегин", issued: "2026-01-10", due: "2026-02-10", returned: "2026-02-08", ext: 0, status: "returned" },
    ];

    const reservations = [
        { book: "Мастер и Маргарита", date: "2026-04-18", pos: 1, expiry: "2026-04-25", status: "ready" },
        { book: "Преступление и наказание", date: "2026-04-19", pos: 2, expiry: "2026-04-26", status: "waiting" },
    ];

    const fines = [
        { reason: "Просрочка возврата", amount: 75, date: "2026-03-26", book: "Чистый код", status: "unpaid" },
    ];

    const statusMap = {
        active: ['Активна', 'st-active'],
        returned: ['Возвращена', 'st-returned'],
        overdue: ['Просрочена', 'st-overdue'],
        ready: ['Готова', 'st-ready'],
        waiting: ['В очереди', 'st-waiting'],
        unpaid: ['Не оплачен', 'st-unpaid'],
        paid: ['Оплачен', 'st-paid'],
    };

    const formatDate = (d) => d ? new Date(d).toLocaleDateString('ru-RU') : '—';

    return (
        <>
            <Header onOpenAbout={() => setShowAbout(true)} />

            <div className="account-header">
                <div className="account-container" style={{padding:0}}>
                    <div className="account-profile">
                        <div className="account-avatar">АК</div>
                        <div>
                            <div className="account-name">Анна Ковалёва</div>
                            <div className="account-ticket">Билет №2026-0421 • Читатель</div>
                            <div className="account-status">✅ Аккаунт верифицирован</div>
                        </div>
                    </div>
                    <div className="account-grid">
                        <div className="account-stat-card">
                            <div className="account-stat-icon" style={{background:'rgba(236,148,40,0.12)'}}>📚</div>
                            <div><div className="account-stat-value">47</div><div className="account-stat-label">Всего выдач</div></div>
                        </div>
                        <div className="account-stat-card">
                            <div className="account-stat-icon" style={{background:'rgba(74,222,128,0.12)'}}>✅</div>
                            <div><div className="account-stat-value">42</div><div className="account-stat-label">Возвращено вовремя</div></div>
                        </div>
                        <div className="account-stat-card">
                            <div className="account-stat-icon" style={{background:'rgba(167,139,250,0.12)'}}>📌</div>
                            <div><div className="account-stat-value">2</div><div className="account-stat-label">Активных броней</div></div>
                        </div>
                        <div className="account-stat-card">
                            <div className="account-stat-icon" style={{background:'rgba(74,222,128,0.12)'}}>💰</div>
                            <div><div className="account-stat-value" style={{color:'var(--green-400)'}}>0 ₽</div><div className="account-stat-label">Задолженность</div></div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="account-container">
                <div className="tabs">
                    <button className={`tab ${activeTab === 'issues' ? 'active' : ''}`} onClick={() => setActiveTab('issues')}>📋 История выдач</button>
                    <button className={`tab ${activeTab === 'reservations' ? 'active' : ''}`} onClick={() => setActiveTab('reservations')}>📌 Активные бронирования</button>
                    <button className={`tab ${activeTab === 'fines' ? 'active' : ''}`} onClick={() => setActiveTab('fines')}>⚠️ Штрафы</button>
                    <button className={`tab ${activeTab === 'settings' ? 'active' : ''}`} onClick={() => setActiveTab('settings')}>⚙️ Настройки</button>
                </div>

                {activeTab === 'issues' && (
                    <div className="table-wrap">
                        <table>
                            <thead><tr><th>Книга</th><th>Дата выдачи</th><th>Вернуть до</th><th>Дата возврата</th><th>Продлений</th><th>Статус</th></tr></thead>
                            <tbody>
                            {issues.map((r,i) => {
                                const [label, cls] = statusMap[r.status] || ['—', ''];
                                return (
                                    <tr key={i}>
                                        <td><strong style={{color:'white'}}>{r.book}</strong></td>
                                        <td>{formatDate(r.issued)}</td>
                                        <td>{formatDate(r.due)}</td>
                                        <td>{formatDate(r.returned)}</td>
                                        <td>{r.ext}</td>
                                        <td><span className={`status-badge ${cls}`}><span className="dot"></span>{label}</span></td>
                                    </tr>
                                );
                            })}
                            </tbody>
                        </table>
                    </div>
                )}

                {activeTab === 'reservations' && (
                    <div className="table-wrap">
                        <table>
                            <thead><tr><th>Книга</th><th>Дата бронирования</th><th>Позиция</th><th>Срок</th><th>Статус</th><th>Действия</th></tr></thead>
                            <tbody>
                            {reservations.map((r,i) => {
                                const [label, cls] = statusMap[r.status] || ['—', ''];
                                return (
                                    <tr key={i}>
                                        <td><strong style={{color:'white'}}>{r.book}</strong></td>
                                        <td>{formatDate(r.date)}</td>
                                        <td>#{r.pos}</td>
                                        <td>{formatDate(r.expiry)}</td>
                                        <td><span className={`status-badge ${cls}`}><span className="dot"></span>{label}</span></td>
                                        <td><button className="btn btn-sm btn-danger">Отменить</button></td>
                                    </tr>
                                );
                            })}
                            </tbody>
                        </table>
                    </div>
                )}

                {activeTab === 'fines' && (
                    <div className="table-wrap">
                        <table>
                            <thead><tr><th>Причина</th><th>Сумма</th><th>Дата</th><th>Книга</th><th>Статус</th></tr></thead>
                            <tbody>
                            {fines.length === 0 ? (
                                <tr><td colSpan="5" className="empty-state" style={{padding:'32px'}}>Задолженность отсутствует</td></tr>
                            ) : fines.map((f,i) => {
                                const [label, cls] = statusMap[f.status] || ['—', ''];
                                return (
                                    <tr key={i}>
                                        <td>{f.reason}</td>
                                        <td><strong style={{color:f.status==='unpaid'?'var(--red-400)':'var(--green-400)'}}>{f.amount} ₽</strong></td>
                                        <td>{formatDate(f.date)}</td>
                                        <td>{f.book}</td>
                                        <td><span className={`status-badge ${cls}`}><span className="dot"></span>{label}</span></td>
                                    </tr>
                                );
                            })}
                            </tbody>
                        </table>
                    </div>
                )}

                {activeTab === 'settings' && (
                    <div className="settings-form">
                        <h3>Личные данные</h3>
                        <label><span>ФИО</span><input defaultValue="Анна Ковалёва" /></label>
                        <label><span>Email</span><input type="email" defaultValue="anna.k@mail.ru" /></label>
                        <label><span>Телефон</span><input type="tel" defaultValue="+7 (916) 123-45-67" /></label>
                        <button className="btn btn-primary">Сохранить изменения</button>
                    </div>
                )}
            </div>

            {showAbout && <AboutModal onClose={() => setShowAbout(false)} />}
        </>
    );
}